function solve(chunks: string[], queries: string[]): number[] {
    // Step 1: Concatenate chunks to form s
    const s = chunks.join('');
    const L = s.length;

    // Use a Map to store the frequency of each maximal word found in s
    const wordCounts = new Map<string, number>();

    // Step 2: Scan s to find all maximal sequences of letters (words)
    let i = 0;
    while (i < L) {
        const char = s[i];

        // Check if the character is a lowercase letter ('a' through 'z')
        if (char >= 'a' && char <= 'z') {
            // Start of a word (maximal sequence of letters)
            const start = i;

            // Consume all contiguous letters
            while (i < L && (s[i] >= 'a' && s[i] <= 'z')) {
                i++;
            }

            const word = s.substring(start, i);

            // Count the word
            wordCounts.set(word, (wordCounts.get(word) || 0) + 1);
        } else {
            // Separator (non-letter characters like '-', space, etc.). Move past it.
            i++;
        }
    }

    // Step 3: Generate results for queries
    const results: number[] = [];
    for (const query of queries) {
        // Since queries are guaranteed to be valid words, we just check the count.
        const count = wordCounts.get(query) || 0;
        results.push(count);
    }

    return results;
}
