    const s = chunks.join('');
    const n = s.length;
    const wordCounts = new Map<string, number>();

    function isLetter(char: string): boolean {
        return char >= 'a' && char <= 'z';
    }

    // Step 1 & 2: Parse s to find all maximal valid words
    let i = 0;
    while (i < n) {
        const char = s[i];

        if (isLetter(char)) {
            // Found the start of a potential word
            const start = i;
            let j = i;

            // Consume characters belonging to the current segment
            while (j < n) {
                const c = s[j];

                if (isLetter(c)) {
                    j++;
                } else if (c === '-') {
                    // Check if this hyphen is validly placed: must have letter neighbors in s
                    const L = j - 1;
                    const R = j + 1;

                    // The preceding character must be a letter (guaranteed if j > start and we extended previously)
                    const isLeftLetter = L >= 0 && isLetter(s[L]);

                    // The succeeding character must be a letter
                    const isRightLetter = R < n && isLetter(s[R]);

                    if (isLeftLetter && isRightLetter) {
                        j++; // Valid hyphen, extend segment
                    } else {
                        // Invalid hyphen placement, segment ends before this character
                        break; 
                    }
                } else { 
                    // Delimiter (space, punctuation, etc.)
                    break; // Segment ends
                }
            }

            // The segment found is s[start...j-1]
            const word = s.substring(start, j);

            // Since we started on a letter and only extended if characters were letters or valid hyphens, 
            // this segment is a maximal valid word.
            wordCounts.set(word, (wordCounts.get(word) || 0) + 1);

            // Move i to the character after the segment we just processed.
            i = j;
        } else {
            // s[i] is a delimiter or invalid char, skip it.
            i++;
        }
    }

    // Step 3: Count occurrences for queries
    const ans: number[] = [];
    for (const query of queries) {
        ans.push(wordCounts.get(query) || 0);
