    const s = chunks.join("");
    const N = s.length;
    const wordCounts = new Map<string, number>();

    const isLetter = (char: string): boolean => {
        return char >= 'a' && char <= 'z';
    };

    /**
     * Checks if the character at index i is valid to be part of a word segment.
     * A character is valid if it is a letter, OR if it is a hyphen flanked by letters.
     */
    const isValidChar = (i: number): boolean => {
        const char = s[i];
        if (isLetter(char)) {
            return true;
        }
        if (char === '-') {
            // Check for flanking letters
            if (i > 0 && i < N - 1 && isLetter(s[i - 1]) && isLetter(s[i + 1])) {
                return true;
            }
        }
        // Any other character (space, digit, non-flanked hyphen, etc.)
        return false;
    };

    let currentWordChars: string[] = [];

    for (let i = 0; i < N; i++) {
        if (isValidChar(i)) {
            currentWordChars.push(s[i]);
        } else {
            // Delimiter found. If we accumulated characters, we found a word.
            if (currentWordChars.length > 0) {
                const word = currentWordChars.join('');
                wordCounts.set(word, (wordCounts.get(word) || 0) + 1);
                currentWordChars = [];
            }
            // If currentWordChars is empty, we just skip the delimiter.
        }
    }

    // Process the last word if the string ended with valid characters
    if (currentWordChars.length > 0) {
        const word = currentWordChars.join('');
        wordCounts.set(word, (wordCounts.get(word) || 0) + 1);
