function solve(chunks: string[], queries: string[]): number[] {
    // Step 1: Construct s
    let s = chunks.join('');

    // Step 2: Preprocessing s to normalize delimiters based on word rules.

    // 2a. Replace any sequence of characters that are NOT lowercase letters or hyphens ([^a-z-]) 
    // with a single space. This handles spaces, punctuation, etc., turning them into delimiters.
    s = s.replace(/[^a-z-]/g, ' ');

    // 2b. Replace any sequence of two or more hyphens (--+) with a single space. 
    // This treats consecutive hyphens as word separators, based on examples.
    s = s.replace(/-{2,}/g, ' ');

    // Step 3: Tokenization
    // Split by one or more spaces and filter out empty strings. These are the valid words.
    const words = s.split(/\s+/).filter(word => word.length > 0);

    // Step 4: Counting
    const wordCounts = new Map<string, number>();
    for (const word of words) {
        wordCounts.set(word, (wordCounts.get(word) || 0) + 1);
    }

    // Step 5: Result Generation
    const ans: number[] = [];
    for (const query of queries) {
        ans.push(wordCounts.get(query) || 0);
    }

    return ans;
}
